+	if _, getErr := store.GetToken(config.DefaultClientName, "old@example.com"); !errors.Is(getErr, keyring.ErrKeyNotFound) {
+		t.Fatalf("expected old token deleted, got %v", getErr)
+	}
+
+	if store.defaultEmail != "new@example.com" {
